{"metadata":{"kernelspec":{"language":"python","display_name":"Python 3","name":"python3"},"language_info":{"name":"python","version":"3.12.12","mimetype":"text/x-python","codemirror_mode":{"name":"ipython","version":3},"pygments_lexer":"ipython3","nbconvert_exporter":"python","file_extension":".py"},"kaggle":{"accelerator":"none","dataSources":[{"sourceId":3136,"databundleVersionId":26502,"sourceType":"competition"}],"dockerImageVersionId":31259,"isInternetEnabled":false,"language":"python","sourceType":"notebook","isGpuEnabled":false}},"nbformat_minor":4,"nbformat":4,"cells":[{"cell_type":"code","source":"#Import\nimport pandas as pd\nimport numpy as np\n\nfrom sklearn.model_selection import train_test_split, cross_val_score\nfrom sklearn.metrics import mean_absolute_error\nfrom sklearn.pipeline import Pipeline\nfrom sklearn.impute import SimpleImputer\n\nfrom xgboost import XGBRegressor\nfrom xgboost import XGBClassifier\n\n#Load data\ntrain_df = pd.read_csv('/kaggle/input/titanic/train.csv')\n\nre_train_df = train_df.copy()\n\n#feature engineering\nre_train_df['Sex_num'] = re_train_df['Sex'].map({'female': 1, 'male': 0})\n\nre_train_df['Has_cabin'] = re_train_df['Cabin'].notna().astype(int)\n\nre_train_df['FamilySize'] = (\n    re_train_df['SibSp'] + re_train_df['Parch'] + 1\n)\n\nre_train_df['FarePerPerson'] = (\n    re_train_df['Fare'] / re_train_df['FamilySize']\n)\n\nre_train_df['IsChild'] = (re_train_df['Age'] < 12).astype(int)\n\nre_train_df['Age'] = re_train_df['Age'].fillna(re_train_df['Age'].median())\n\n#re_train_df['IsElderly'] = (re_train_df['Age'] > 60).astype(int)\n\n#target (what to predict)\ny = re_train_df['Survived']\n#y = train_df['Survived']\n\n#freatures \nfeatures = [\n    \"Pclass\", \"Age\", \"SibSp\", \"Parch\", \"FarePerPerson\", \n    \"Sex_num\", \"Has_cabin\", \"IsChild\"\n]\n\nX = re_train_df[features]\n#X = train_df[features]\n\nxgb_pipeline = Pipeline(steps=[\n    (\"imputer\", SimpleImputer(strategy=\"median\")),\n    (\"model\", XGBClassifier(\n        n_estimators=300,\n        learning_rate=0.05,\n        max_depth=4,\n        subsample=0.8,\n        colsample_bytree=0.8,\n        random_state=42\n    ))\n])\nscores = cross_val_score(\n    xgb_pipeline,\n    X,\n    y,\n    cv=5,\n    scoring=\"accuracy\"\n)\n\n\n#print(\"MAE:\", -scores.mean())\nprint(\"Accuracy:\", scores.mean())\n\n# Train final model on full training data\nxgb_pipeline.fit(X, y)\n\n# Prepare test features\ntest_xgb = pd.read_csv('/kaggle/input/titanic/test.csv')\n\n# Apply same feature engineering to test data\ntest_xgb['Sex_num'] = test_xgb['Sex'].map({'female': 1, 'male': 0})\ntest_xgb['Has_cabin'] = test_xgb['Cabin'].notna().astype(int)\ntest_xgb['FamilySize'] = test_xgb['SibSp'] + test_xgb['Parch'] + 1\ntest_xgb['FarePerPerson'] = test_xgb['Fare'] / test_xgb['FamilySize']\ntest_xgb['IsChild'] = (test_xgb['Age'] < 12).astype(int)\n#test_xgb['IsElderly'] = (test_xgb['Age'] > 60).astype(int)\n\nX_test = test_xgb[features]\n\n# Predict\ntest_preds = xgb_pipeline.predict(X_test)\n\n# Create submission file\nsubmission = pd.DataFrame({\n    \"PassengerId\": test_xgb[\"PassengerId\"],\n    \"Survived\": test_preds\n})\n\nsubmission.to_csv(\"submission.csv\", index=False)","metadata":{"_uuid":"8f2839f25d086af736a60e9eeb907d3b93b6e0e5","_cell_guid":"b1076dfc-b9ad-4769-8c92-a6c4dae69d19","trusted":true,"execution":{"iopub.status.busy":"2026-01-22T09:15:45.224264Z","iopub.execute_input":"2026-01-22T09:15:45.225336Z","iopub.status.idle":"2026-01-22T09:15:45.967366Z","shell.execute_reply.started":"2026-01-22T09:15:45.225298Z","shell.execute_reply":"2026-01-22T09:15:45.966684Z"}},"outputs":[{"name":"stdout","text":"Accuracy: 0.8350197727700708\n","output_type":"stream"}],"execution_count":3},{"cell_type":"code","source":"","metadata":{"trusted":true},"outputs":[],"execution_count":null}]}